#!/usr/bin/env python3\n\"\"\"\nTest script to verify backend functionality.\nCreates sample data and tests API endpoints.\n\"\"\"\n\nimport sys\nimport requests\nfrom datetime import datetime, timedelta\nimport json\n\nBASE_URL = \"http://localhost:8000\"\n\ndef test_health_check():\n    \"\"\"Test API health endpoint\"\"\"\n    print(\"\\n=== Testing Health Check ===\")\n    try:\n        response = requests.get(f\"{BASE_URL}/health\")\n        print(f\"Status: {response.status_code}\")\n        print(f\"Response: {response.json()}\")\n        return response.status_code == 200\n    except Exception as e:\n        print(f\"Error: {e}\")\n        return False\n\ndef create_sample_supplier():\n    \"\"\"Create a sample supplier\"\"\"\n    print(\"\\n=== Creating Sample Supplier ===\")\n    supplier_data = {\n        \"supplier_name\": \"Global Supply Co\",\n        \"contact_person\": \"John Doe\",\n        \"email\": \"contact@globalsupply.com\",\n        \"phone\": \"+1-555-0123\",\n        \"city\": \"New York\",\n        \"country\": \"USA\",\n        \"rating\": 5\n    }\n    \n    try:\n        response = requests.post(f\"{BASE_URL}/api/suppliers/\", json=supplier_data)\n        print(f\"Status: {response.status_code}\")\n        if response.status_code == 201:\n            supplier = response.json()\n            print(f\"Created Supplier ID: {supplier['id']}\")\n            return supplier['id']\n        else:\n            print(f\"Response: {response.json()}\")\n            return None\n    except Exception as e:\n        print(f\"Error: {e}\")\n        return None\n\ndef create_sample_product(supplier_id):\n    \"\"\"Create a sample product\"\"\"\n    print(\"\\n=== Creating Sample Product ===\")\n    product_data = {\n        \"product_name\": \"Industrial Widget\",\n        \"sku\": \"WDG-001\",\n        \"category\": \"Hardware\",\n        \"description\": \"High-quality industrial widget\",\n        \"unit_price\": 49.99,\n        \"supplier_id\": supplier_id,\n        \"reorder_level\": 20\n    }\n    \n    try:\n        response = requests.post(f\"{BASE_URL}/api/products/\", json=product_data)\n        print(f\"Status: {response.status_code}\")\n        if response.status_code == 201:\n            product = response.json()\n            print(f\"Created Product ID: {product['id']}\")\n            return product['id']\n        else:\n            print(f\"Response: {response.json()}\")\n            return None\n    except Exception as e:\n        print(f\"Error: {e}\")\n        return None\n\ndef create_sample_order(product_id, supplier_id):\n    \"\"\"Create a sample order with analytics\"\"\"\n    print(\"\\n=== Creating Sample Order with Analytics ===\")\n    \n    now = datetime.now()\n    order_data = {\n        \"order_number\": f\"ORD-TEST-{int(now.timestamp())}\",\n        \"product_id\": product_id,\n        \"supplier_id\": supplier_id,\n        \"quantity\": 100,\n        \"unit_price\": 49.99,\n        \"order_placed_at\": now.isoformat(),\n        \"procurement_completed_at\": (now + timedelta(hours=30)).isoformat(),\n        \"processing_completed_at\": (now + timedelta(hours=50)).isoformat(),\n        \"dispatched_at\": (now + timedelta(hours=60)).isoformat(),\n        \"delivered_at\": (now + timedelta(hours=120)).isoformat(),\n        \"status\": \"delivered\"\n    }\n    \n    try:\n        response = requests.post(f\"{BASE_URL}/api/orders/\", json=order_data)\n        print(f\"Status: {response.status_code}\")\n        if response.status_code == 201:\n            order = response.json()\n            print(f\"\\nCreated Order ID: {order['id']}\")\n            print(f\"Order Number: {order['order_number']}\")\n            print(f\"\\nAnalytics Results:\")\n            print(f\"  - Procurement Time: {order['procurement_time']} hours\")\n            print(f\"  - Processing Time: {order['processing_time']} hours\")\n            print(f\"  - Dispatch Time: {order['dispatch_time_duration']} hours\")\n            print(f\"  - Delivery Time: {order['delivery_time_duration']} hours\")\n            print(f\"  - Total Time: {order['total_time']} hours\")\n            print(f\"  - SLA Breach: {order['sla_breach']}\")\n            print(f\"  - Breached Stage: {order['breached_stage']}\")\n            print(f\"  - Bottleneck Stage: {order['bottleneck_stage']}\")\n            return order['id']\n        else:\n            print(f\"Response: {response.json()}\")\n            return None\n    except Exception as e:\n        print(f\"Error: {e}\")\n        return None\n\ndef test_analytics_summary():\n    \"\"\"Test analytics summary endpoint\"\"\"\n    print(\"\\n=== Testing Analytics Summary ===\")\n    try:\n        response = requests.get(f\"{BASE_URL}/api/orders/analytics/summary\")\n        print(f\"Status: {response.status_code}\")\n        if response.status_code == 200:\n            analytics = response.json()\n            print(f\"\\nAnalytics Summary:\")\n            print(f\"  - Total Orders: {analytics['total_orders']}\")\n            print(f\"  - SLA Breach Count: {analytics['sla_breach_count']}\")\n            print(f\"  - SLA Compliance Rate: {analytics['sla_compliance_rate']}%\")\n            print(f\"  - Avg Total Time: {analytics['avg_total_time']} hours\")\n            print(f\"  - Bottleneck Summary: {analytics['bottleneck_summary']}\")\n            return True\n        else:\n            print(f\"Response: {response.json()}\")\n            return False\n    except Exception as e:\n        print(f\"Error: {e}\")\n        return False\n\ndef test_forecast_overview():\n    \"\"\"Test forecast overview endpoint\"\"\"\n    print(\"\\n=== Testing Forecast Overview ===\")\n    try:\n        response = requests.get(f\"{BASE_URL}/api/forecast/overview\")\n        print(f\"Status: {response.status_code}\")\n        if response.status_code == 200:\n            data = response.json()\n            print(f\"Response: {json.dumps(data, indent=2)}\")\n            return True\n        else:\n            print(f\"Response: {response.json()}\")\n            return False\n    except Exception as e:\n        print(f\"Error: {e}\")\n        return False\n\ndef main():\n    \"\"\"Run all tests\"\"\"\n    print(\"=\"*60)\n    print(\"Supply Chain Analytics Backend - Test Suite\")\n    print(\"=\"*60)\n    \n    # Test health check\n    if not test_health_check():\n        print(\"\\n❌ Health check failed. Make sure the server is running.\")\n        print(\"Start server with: python main.py\")\n        sys.exit(1)\n    \n    print(\"\\n✅ Health check passed\")\n    \n    # Create test data\n    supplier_id = create_sample_supplier()\n    if not supplier_id:\n        print(\"\\n❌ Failed to create supplier\")\n        return\n    \n    product_id = create_sample_product(supplier_id)\n    if not product_id:\n        print(\"\\n❌ Failed to create product\")\n        return\n    \n    order_id = create_sample_order(product_id, supplier_id)\n    if not order_id:\n        print(\"\\n❌ Failed to create order\")\n        return\n    \n    # Test analytics\n    test_analytics_summary()\n    test_forecast_overview()\n    \n    print(\"\\n\" + \"=\"*60)\n    print(\"✅ All tests completed successfully!\")\n    print(\"=\"*60)\n    print(f\"\\nAPI Documentation: {BASE_URL}/docs\")\n    print(f\"ReDoc: {BASE_URL}/redoc\")\n\nif __name__ == \"__main__\":\n    main()\n